import logo from "../assets/basiclogo1.png"; // FIX PATH IF NEEDED
// import DarkModeToggle from "./DarkModeToggle";

export default function Header({ darkMode, setDarkMode }) {
  return (
    <header className="w-full px-4 lg:px-12 py-4 flex items-center justify-between bg-white text-slate-800 shadow-sm sticky top-0 z-50">
      <div className="flex items-center gap-2">
        <img src={logo} alt="CollegeReview" className="h-8 w-auto" />
        <span className="text-2xl font-bold tracking-tight text-slate-900">
          CollegeReview
        </span>
      </div>

    </header>
  );
}
